const frm_gen_origen_pagina_inicio = this.frm_gen_origen_pagina_inicio
const frm_gen_origen_pagina_coberturas = this.frm_gen_origen_pagina_coberturas
const frm_gen_origen_pagina_pricing = this.frm_gen_origen_pagina_pricing
const frm_gen_origen_pagina_resumen = this.frm_gen_origen_pagina_resumen
const frm_gen_origen_pagina_terminos_condiciones = this.frm_gen_origen_pagina_terminos_condiciones

let origen = null

if (frm_gen_origen_pagina_inicio === 1) {
  origen = "inicio"
} else if (frm_gen_origen_pagina_coberturas === 1) {
  origen = "coberturas"
} else if (frm_gen_origen_pagina_pricing === 1) {
  origen = "pricing"
} else if (frm_gen_origen_pagina_resumen === 1) {
  origen = "resumen"
} else if (frm_gen_origen_pagina_terminos_condiciones === 1) {
  origen = "terminos_condiciones"
}

console.log("origen" + origen)

return origen

setTimeout(() => {
  const modalComponent = document.querySelector(
    '[custom-css-selector="css_modal_terminos_condiciones"]'
  );

  if (!modalComponent || !modalComponent.__vue__) {
    return;
  }

  const vueInstance = modalComponent.__vue__;

  vueInstance.$root.$on("bv::modal::show", (bvEvent, modalId) => {
    const modal = bvEvent.vueTarget;

    if (modalId === "modal_terminos_condiciones") {
      modal.onOk = () => {
        const loader = document.getElementById(
          "global-loader-overlay-terminos-condiciones-slip"
        );

        const submitBtn = document.querySelector(
          'button[name="frm_decision_evaluacion_riesgo_continuar_generar_slip"]'
        );

        const frm_valor_asegurado_control_procede =
          vueInstance.frm_valor_asegurado_control_procede;

        if (frm_valor_asegurado_control_procede == false) {
          vueInstance.$root.$bvModal.show(
            "modal_alert_valorAsegDeduc_alMenosUnValor"
          );
          modal.hide();
          if (loader) loader.classList.remove("show");
          return;
        }

        // VALIDACIÓN ERRORES VISIBLES
        const erroresCustom      = document.querySelectorAll('[selector="text-invalid"]');
        const erroresCustomTable = document.querySelectorAll('[selector="text-invalid-in-table"]');
        const erroresBootstrap   = document.querySelectorAll(".invalid-feedback");
        const erroresVisibles    = [];

        erroresCustom.forEach((div) => {
          const visible = div.offsetParent !== null;
          const mensaje = div.textContent.trim().toLowerCase();
          if (visible) erroresVisibles.push(mensaje);
        });

        erroresCustomTable.forEach((div) => {
          const visible = div.offsetParent !== null;
          const mensaje = div.textContent.trim().toLowerCase();
          if (visible) erroresVisibles.push(mensaje);
        });

        erroresBootstrap.forEach((div) => {
          const visible =
            div.offsetParent !== null && div.classList.contains("d-block");
          const mensaje = div.textContent.trim().toLowerCase();
          if (visible) erroresVisibles.push(mensaje);
        });

        if (erroresVisibles.length > 0) {
          if (loader) loader.classList.remove("show");
          vueInstance.$root.$bvModal.show("modal_accion_requerida");
          modal.hide();
          return;
        }

        // SI NO HAY ERRORES → SUBMIT
        if (submitBtn) {
          submitBtn.click();
        }

        // ESPERAR Y BUSCAR ALERT
        setTimeout(() => {
          const alertError = document.querySelector(
            '.alert.alert-danger[role="alert"]'
          );

          if (alertError) {
            const texto = alertError.textContent.toLowerCase();
            if (
              texto.includes("errores de validación") ||
              texto.includes("error de validación")
            ) {
              if (loader) loader.classList.remove("show");
              vueInstance.$root.$bvModal.show("modal_accion_requerida");
              modal.hide();
              return;
            }
          }

          if (loader) loader.classList.add("show");
        }, 400);

        modal.hide();
      };
    }
  });
}, 500);

setTimeout(() => {
  const OVERLAY_ID = "global-loader-overlay-terminos-condiciones-slip";
  const TEXT_ID = "global-loader-text-terminos-condiciones-slip";
  const INTERVAL_MS = 6000;
  const MENSAJES = ["Procesando...", "Recopilando la información...", 
  "Procesando...", "Revisando el contenido...", 
  "Procesando...", "Un momento...",
  "Procesando...", "Generando Slip..."
  ];

  let timer = null;
  let i = 0;
  let overlay = null;
  let textEl = null;
  let observer = null;

  const isVisible = (el) => {
    if (!el) return false;
    const cs = window.getComputedStyle(el);
    return cs.display !== "none" && cs.visibility !== "hidden" && cs.opacity !== "0";
  };

  const findOverlay = () => document.getElementById(OVERLAY_ID);

  const findTextEl = (ov) => {
    let t = document.getElementById(TEXT_ID);
    if (t) return t;

    t = ov.querySelector(`[id="${TEXT_ID}"]`)
      || ov.querySelector("[data-loader-text]")
      || ov.querySelector("div:last-child");

    return t;
  };

  const stop = () => {
    if (timer) clearInterval(timer);
    timer = null;
    i = 0;
    if (textEl) textEl.textContent = "Procesando...";
  };

  const start = () => {
    overlay = findOverlay();
    if (!overlay) return;

    textEl = findTextEl(overlay);

    if (!textEl) {
      textEl = document.createElement("div");
      textEl.id = TEXT_ID;
      textEl.style.cssText = "margin-top:10px;font-weight:bold;color:#2167ae;";
      overlay.appendChild(textEl);
    }

    if (timer) return;

    i = 0;
    textEl.textContent = MENSAJES[i];

    timer = setInterval(() => {
      if (!isVisible(overlay)) {
        stop();
        return;
      }
      i = (i + 1) % MENSAJES.length;
      textEl.textContent = MENSAJES[i];
    }, INTERVAL_MS);
  };

  const init = () => {
    overlay = findOverlay();

    if (!overlay) {
      setTimeout(init, 300);
      return;
    }

    observer = new MutationObserver(() => {
      if (overlay.classList.contains("show") && isVisible(overlay)) start();
      if (!overlay.classList.contains("show") || !isVisible(overlay)) stop();
    });

    observer.observe(overlay, { attributes: true, attributeFilter: ["class", "style"] });

    if (isVisible(overlay)) start();

    window.loaderTextRotateStart = start;
    window.loaderTextRotateStop = stop;
  };

  if (document.readyState === "loading") {
    document.addEventListener("DOMContentLoaded", () => setTimeout(init, 0));
  } else {
    setTimeout(init, 0);
  }
}, 500);
